-		return ""
-	}
+		file, err := sessionTree.File(paths.PromptFileName)
+		if err != nil {
+			continue
+		}

-	content, err := file.Contents()
-	if err != nil {
-		return ""
+		content, err := file.Contents()
+		if err != nil {
+			continue
+		}
+
+		if prompt := ExtractFirstPrompt(content); prompt != "" {
+			return prompt
+		}
 	}

-	return ExtractFirstPrompt(content)
+	return ""
 }

